import{_ as e,c as n,o as t,a7 as a}from"./chunks/framework.1gbG0lGE.js";const b=JSON.parse('{"title":"Git management","description":"","frontmatter":{},"headers":[],"relativePath":"engines/lesli/contributing/git-flow.md","filePath":"engines/lesli/contributing/git-flow.md","lastUpdated":1715574060000}'),r={name:"engines/lesli/contributing/git-flow.md"},o=a('<h1 id="git-management" tabindex="-1">Git management <a class="header-anchor" href="#git-management" aria-label="Permalink to &quot;Git management&quot;">​</a></h1><p>Lesli uses git and github to build versions of all software products.</p><h2 id="git-branching" tabindex="-1">Git branching <a class="header-anchor" href="#git-branching" aria-label="Permalink to &quot;Git branching&quot;">​</a></h2><p>To avoid conflicts between requirements developers must create a git branch to code the current requirement they are working on.</p><p>In this case a Trello card, Github issue, Lesli or any other id is equal to a requirement, developers can push all the needed commits to complete the feature required to their current working branch.</p><p>A requirement can be: a new functionality, bug fixes and improvements.</p><h3 id="branching-system" tabindex="-1">Branching system <a class="header-anchor" href="#branching-system" aria-label="Permalink to &quot;Branching system&quot;">​</a></h3><p><strong>Features</strong>: Every requirement must be developed on his own branch. <strong>Version</strong>: Contains a set of requirements planned to be released within a specific version. <strong>Master</strong>: Main development branch, all features branches send PR to this branch. This branch has the latest features. <strong>Test</strong>: Branch for testing and QA (this branch is a previous step for production), only version and/or master can send PR to this branch. <strong>Production</strong>: Stable branch for production environment, only the test branch can send PR to this branch. <strong>Hotfix</strong>: Branch forked from production created to fix only on bugs or important changes that needs to be fixed urgently for production.</p><h2 id="maintenance-branches" tabindex="-1">Maintenance branches <a class="header-anchor" href="#maintenance-branches" aria-label="Permalink to &quot;Maintenance branches&quot;">​</a></h2><p>As a good practice we keep a branch with the source code for every major and minor version for all our gem-like engines, including builder engines and the core itself.</p><p>Every repository should contain dedicated branches for every released version, for example: cloud_babel v1.0.0 belongs to the branch version-1.0.0; The goal of this approach is to continue supporting older versions of our software. providing an easy way to access to the source code of the different implementations of The Lesli Platform core, engines and builders.</p><p>This branch must be created manually just before a Git tag is created for #major or #minor version.</p>',12),i=[o];function s(c,h,l,d,u,g){return t(),n("div",null,i)}const p=e(r,[["render",s]]);export{b as __pageData,p as default};
